const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json || {};
return [{ json: Object.assign({}, r, { data: data }) }];

// Render the annual awareness calendar as a designed PDF planner (plus an .ics
// feed). Two configurable layouts:
//   year  — a "year on a page" planner (A4 landscape, 12 month cards)
//   month — a month-per-page wall calendar (A4 portrait, cover + 12 day-grids)
// Brand kit (Jarvis avatar/sign-off, navy/teal/gold) shared with the rest of the kit.
var __jfs=null; try{__jfs=require('fs');}catch(e){}
function jAvatarUri(){ if(!__jfs) return ''; var t=[['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for(var i=0;i<t.length;i++){ try{ return 'data:'+t[i][1]+';base64,'+__jfs.readFileSync(t[i][0]).toString('base64'); }catch(e){} } return ''; }
var JKIT_SVG='<svg class="jav" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="jkitg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0E7C86"/><stop offset="1" stop-color="#0A1A2F"/></linearGradient></defs><circle cx="32" cy="32" r="32" fill="url(#jkitg)"/><rect x="19" y="21" width="26" height="22" rx="7" fill="#fff"/><circle cx="27" cy="32" r="3.2" fill="#0E7C86"/><circle cx="37" cy="32" r="3.2" fill="#0E7C86"/><rect x="27" y="38" width="10" height="2.4" rx="1.2" fill="#0E7C86"/><rect x="30.7" y="14" width="2.6" height="6" rx="1.3" fill="#9fe4d8"/><circle cx="32" cy="13" r="2.4" fill="#E7C76A"/><path d="M23 47h18l-3 4.5H26z" fill="#9fe4d8"/></svg>';
var AV = jAvatarUri(); var AVATAR = AV ? ('<img src="'+AV+'"/>') : JKIT_SVG;

const r = $json || {};
const d = r.data || {};
const year = r.year || new Date().getFullYear();
const client = (r.client || '').toString();
const brand = client ? client : 'Security Awareness';
const layout = (r.layout === 'month') ? 'month' : 'year';
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function arr(x){ return Array.isArray(x)?x:(x==null||x===''?[]:[x]); }
const MON = ['january','february','march','april','may','june','july','august','september','october','november','december'];
const MN = ['January','February','March','April','May','June','July','August','September','October','November','December'];
function midx(name){ var n=String(name||'').toLowerCase().slice(0,3); for(var k=0;k<12;k++){ if(MON[k].slice(0,3)===n) return k; } return -1; }
// Per-month accent palette (seasonal, brand-aligned).
const AC = ['#2D6CB5','#0E7C86','#1F8A4C','#5FA83C','#8FAE1F','#C9A24B','#E0902B','#D9722B','#C0562B','#B02525','#7A3FB0','#324A6B'];

// Order the AI's months into calendar slots (fall back to positional, fill gaps).
let raw = arr(d.months);
const ordered = new Array(12).fill(null);
raw.slice(0,12).forEach(function(m,pos){ var mi=midx(m && m.month); if(mi<0) mi=pos; if(mi>=0 && mi<12 && !ordered[mi]) ordered[mi]=m; });
for(var k=0;k<12;k++){ if(!ordered[k]) ordered[k]={month:MN[k],theme:'',focus:'',channels:[],keyDates:[],ideas:[]}; }

function chips(list){ var a=arr(list); if(!a.length) return ''; return '<div class="chips">'+a.slice(0,4).map(function(c){return '<span class="chip">'+esc(c)+'</span>';}).join('')+'</div>'; }
function bullets(list){ var a=arr(list); if(!a.length) return ''; return '<ul>'+a.slice(0,4).map(function(x){return '<li>'+esc(x)+'</li>';}).join('')+'</ul>'; }
// A real day-grid for a given month (Mon-first), weekends shaded.
function dayGrid(y, mi){
  var first=new Date(y, mi, 1).getDay(); var start=(first+6)%7; var days=new Date(y, mi+1, 0).getDate();
  var weeks=Math.ceil((start+days)/7);
  var head='<tr>'+['M','T','W','T','F','S','S'].map(function(dn,i){return '<th'+(i>=5?' class="we"':'')+'>'+dn+'</th>';}).join('')+'</tr>';
  var body='';
  for(var w=0; w<weeks; w++){ var tds='';
    for(var dd=0; dd<7; dd++){ var day=w*7+dd-start+1; var we=dd>=5?' we':'';
      tds += (day<1||day>days) ? '<td class="empty'+we+'"></td>' : '<td class="day'+we+'"><span>'+day+'</span></td>';
    }
    body+='<tr>'+tds+'</tr>';
  }
  return '<table class="cal"><thead>'+head+'</thead><tbody>'+body+'</tbody></table>';
}

const sub = (r.focus ? ('Focus: '+esc(r.focus)+' &middot; ') : '') + 'Audience: '+esc(r.audience||'All staff');
const takeaways = arr(d.takeaways).length ? arr(d.takeaways) : arr(d.priorities);

let html = '';
if (layout === 'year') {
  // ---------- YEAR ON A PAGE (A4 landscape) ----------
  const CSS = "@page{size:A4 landscape;margin:7mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#16202b}"
    +".top{display:flex;align-items:center;justify-content:space-between;background:linear-gradient(120deg,#0A1A2F,#0E7C86);color:#fff;border-radius:12px;padding:9px 16px;margin-bottom:7px}"
    +".top .k{font-size:9pt;letter-spacing:4px;text-transform:uppercase;color:#E7C76A;font-weight:800}"
    +".top h1{margin:2px 0 0;font-size:21pt;font-weight:800}.top .s{font-size:9.5pt;color:#cfe0e6;margin-top:3px}"
    +".top .yr{display:flex;align-items:center;gap:12px}.top .yr .y{font-family:Georgia,serif;font-size:30pt;font-weight:700;color:#fff}.top .yr img,.top .yr .jav{width:46px;height:46px;border-radius:50%;border:2px solid #9fe4d8}"
    +".grid{display:grid;grid-template-columns:repeat(4,1fr);gap:6px}"
    +".mc{border:1px solid #E2E6EC;border-radius:9px;overflow:hidden;background:#fff;display:flex;flex-direction:column;min-height:43mm}"
    +".mc .mh{padding:6px 11px;color:#fff;display:flex;align-items:baseline;justify-content:space-between}"
    +".mc .mh .mn{font-size:12.5pt;font-weight:800;letter-spacing:.5px}.mc .mh .mt{font-size:8.5pt;font-weight:700;opacity:.92;text-align:right;max-width:60%}"
    +".mc .mb{padding:8px 11px;font-size:8.5pt;color:#46505c;line-height:1.35;flex:1}"
    +".mc .fc{color:#16202b;font-weight:600;margin:0 0 5px}"
    +".chips{display:flex;flex-wrap:wrap;gap:4px;margin:5px 0}.chip{background:#EaF4F3;color:#0E7C86;border:1px solid #cfe7e4;border-radius:11px;padding:1px 8px;font-size:7.5pt;font-weight:700}"
    +".kd{margin-top:4px;color:#7a3f10}.kd b{color:#B8860B}"
    +".pri{display:flex;gap:8px;align-items:center;margin:6px 0 5px;font-size:8.5pt;color:#46505c}.pri b{color:#0A1A2F;text-transform:uppercase;letter-spacing:1px;font-size:7.5pt}"
    +".foot{margin-top:6px;border-top:1px solid #E2E6EC;padding-top:5px;color:#8a98a4;font-size:7.5pt;display:flex;justify-content:space-between}";
  var cards = ordered.map(function(m, i){
    var kd = arr(m.keyDates).slice(0,2);
    return '<div class="mc"><div class="mh" style="background:'+AC[i]+'"><span class="mn">'+MN[i]+'</span>'+(m.theme?'<span class="mt">'+esc(m.theme)+'</span>':'')+'</div>'
      +'<div class="mb">'+(m.focus?'<div class="fc">'+esc(m.focus)+'</div>':'')
      + chips(m.channels)
      + (kd.length?('<div class="kd"><b>Dates:</b> '+kd.map(function(x){return esc(x);}).join(' · ')+'</div>'):'')
      +'</div></div>';
  }).join('');
  var pri = takeaways.length ? ('<div class="pri"><b>Programme priorities</b><span>'+takeaways.slice(0,3).map(function(t){return esc(t);}).join('  ·  ')+'</span></div>') : '';
  html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'
    +'<div class="top"><div><div class="k">Security Awareness Calendar</div><h1>'+esc(brand)+'</h1><div class="s">'+sub+'</div></div>'
    +'<div class="yr">'+AVATAR+'<span class="y">'+year+'</span></div></div>'
    + pri
    +'<div class="grid">'+cards+'</div>'
    +'<div class="foot"><span>'+esc(brand)+' · AI-generated — review &amp; adapt before scheduling</span><span>Jarvis · '+year+'</span></div>'
    +'</body></html>';
} else {
  // ---------- MONTH PER PAGE (A4 portrait): cover + 12 day-grids ----------
  const CSS = "@page{size:A4 portrait;margin:0} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#16202b}"
    +".cover{height:297mm;background:radial-gradient(120% 80% at 80% 0%,#13507a 0,#0A1A2F 55%),linear-gradient(160deg,#0A1A2F,#0E7C86 160%);color:#fff;padding:28mm 24mm;display:flex;flex-direction:column;justify-content:space-between;break-after:page}"
    +".cover .k{font-size:12pt;letter-spacing:6px;text-transform:uppercase;color:#E7C76A;font-weight:800}"
    +".cover h1{font-size:46pt;line-height:1.03;margin:10px 0 0;font-weight:800}.cover .y{font-family:Georgia,serif;font-size:64pt;font-weight:700;margin-top:6px}"
    +".cover .s{font-size:13pt;color:#cfe0e6;margin-top:10px}"
    +".cover .toc{margin-top:14mm;column-count:2;column-gap:14mm}.cover .toc div{break-inside:avoid;padding:5px 0;border-top:1px solid rgba(159,228,216,.25);font-size:10.5pt;color:#eaf2f5}.cover .toc b{color:#9fe4d8}"
    +".cover .by{display:flex;align-items:center;gap:12px}.cover .by img,.cover .by .jav{width:54px;height:54px;border-radius:50%;border:2px solid #9fe4d8}.cover .by .nm{font-family:Georgia,serif;font-size:13pt;font-weight:700}.cover .by .rl{font-size:8.5pt;letter-spacing:2px;text-transform:uppercase;color:#9fe4d8;font-weight:800}"
    +".mp{height:297mm;padding:16mm 18mm;display:flex;flex-direction:column;break-before:page}"
    +".mp .mh{color:#fff;border-radius:12px;padding:14px 20px;display:flex;align-items:baseline;justify-content:space-between}"
    +".mp .mh .mn{font-size:26pt;font-weight:800}.mp .mh .mt{font-size:13pt;font-weight:700;opacity:.95;max-width:60%;text-align:right}"
    +".mp .row{display:flex;gap:16px;margin-top:14px;flex:1}"
    +"table.cal{border-collapse:collapse;width:118mm;table-layout:fixed}"
    +"table.cal th{font-size:9pt;color:#0A1A2F;padding:6px 0;text-transform:uppercase;letter-spacing:1px}table.cal th.we{color:#0E7C86}"
    +"table.cal td{border:1px solid #E2E6EC;height:15mm;vertical-align:top}table.cal td.empty{background:#fafbfc;border-color:#eef1f5}table.cal td.we{background:#f5f9f9}table.cal td span{display:block;padding:4px 6px;font-size:10pt;color:#46505c;font-weight:600}"
    +".info{flex:1}.info h3{font-size:9pt;letter-spacing:2px;text-transform:uppercase;color:#0E7C86;font-weight:800;margin:0 0 5px}.info .fc{font-size:11.5pt;color:#16202b;line-height:1.45;margin:0 0 12px}"
    +".chips{display:flex;flex-wrap:wrap;gap:6px;margin:0 0 12px}.chip{background:#EaF4F3;color:#0E7C86;border:1px solid #cfe7e4;border-radius:13px;padding:3px 11px;font-size:9pt;font-weight:700}"
    +".info ul{margin:4px 0 12px;padding-left:18px}.info li{font-size:10.5pt;color:#46505c;margin:4px 0;line-height:1.4}"
    +".sign{display:flex;align-items:center;gap:11px;margin-top:auto;padding-top:12px;border-top:2px solid #0E7C86}.sign img,.sign .jav{width:42px;height:42px;border-radius:50%;border:2px solid #0E7C86}.sign .nm{font-family:Georgia,serif;font-size:13pt;color:#0A1A2F;font-weight:700}.sign .rl{font-size:8pt;letter-spacing:2px;text-transform:uppercase;color:#0E7C86;font-weight:800}.sign .pg{margin-left:auto;color:#8a98a4;font-size:9pt}";
  var toc = ordered.map(function(m,i){ return '<div><b>'+MN[i].slice(0,3)+'</b> &middot; '+esc(m.theme||'Awareness')+'</div>'; }).join('');
  var cover = '<section class="cover"><div><div class="k">Security Awareness Calendar</div><h1>'+esc(brand)+'</h1><div class="y">'+year+'</div><div class="s">'+sub+'</div>'
    +'<div class="toc">'+toc+'</div></div>'
    +'<div class="by">'+AVATAR+'<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Assistant</div></div></div></section>';
  var pages = ordered.map(function(m,i){
    return '<section class="mp"><div class="mh" style="background:linear-gradient(120deg,'+AC[i]+',#0A1A2F)"><span class="mn">'+MN[i]+' '+year+'</span>'+(m.theme?'<span class="mt">'+esc(m.theme)+'</span>':'')+'</div>'
      +'<div class="row"><div>'+dayGrid(year, i)+'</div>'
      +'<div class="info">'+(m.focus?'<h3>Focus</h3><div class="fc">'+esc(m.focus)+'</div>':'')
      + (arr(m.channels).length?'<h3>Channels</h3>'+chips(m.channels):'')
      + (arr(m.keyDates).length?'<h3>Key dates</h3>'+bullets(m.keyDates):'')
      + (arr(m.ideas).length?'<h3>Activity ideas</h3>'+bullets(m.ideas):'')
      +'</div></div>'
      +'<div class="sign">'+AVATAR+'<div><div class="nm">Jarvis</div><div class="rl">Awareness Programme</div></div><span class="pg">'+esc(brand)+' · '+(i+1)+' / 12</span></div>'
      +'</section>';
  }).join('');
  html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'+cover+pages+'</body></html>';
}

// .ics — one all-day VEVENT per month (launch of the month theme)
function pad(n){ return (n<10?'0':'')+n; }
const stamp = new Date().toISOString().replace(/[-:]/g,'').replace(/\.\d+Z$/,'Z');
let ics = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//Jarvis//Awareness Calendar//EN','CALSCALE:GREGORIAN','METHOD:PUBLISH'];
ordered.forEach(function(m,mi){ var dt=String(year)+pad(mi+1)+'01'; var dtend=String(year)+pad(mi+1)+'02'; var theme=(m.theme||(MN[mi]+' awareness')); ics.push('BEGIN:VEVENT'); ics.push('UID:jarvis-'+year+'-'+pad(mi+1)+'@awareness'); ics.push('DTSTAMP:'+stamp); ics.push('DTSTART;VALUE=DATE:'+dt); ics.push('DTEND;VALUE=DATE:'+dtend); ics.push('SUMMARY:'+String(theme).replace(/[\r\n]+/g,' ')); var desc=[m.focus, (arr(m.channels).length?('Channels: '+arr(m.channels).join(', ')):''), (arr(m.ideas).length?('Ideas: '+arr(m.ideas).join('; ')):'')].filter(Boolean).join(' \\n '); if(desc) ics.push('DESCRIPTION:'+desc.replace(/[\r\n]+/g,' ')); ics.push('END:VEVENT'); });
ics.push('END:VCALENDAR');
const icsStr = ics.join('\r\n')+'\r\n';

return [{ json: { html: html, ics: icsStr, topic: r.topic||('Awareness campaign '+year), date: r.date, fileSafe: r.fileSafe||('campaign-'+year), outDir: 'calendar', filePrefix: 'calendar' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'calendar');
const base = (meta.filePrefix || 'calendar') + '-' + (meta.fileSafe || 'item') + '-' + meta.date;
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
try { if (buf) fs.writeFileSync(dir + '/' + base + '.pdf', buf); } catch (e) {}
try { if (meta.ics) fs.writeFileSync(dir + '/' + base + '.ics', meta.ics); } catch (e) {}
const out = { json: { ok: !!buf, pdf: dir + '/' + base + '.pdf', ics: dir + '/' + base + '.ics', topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = base + '.pdf'; out.binary = { data: b.data }; } } catch (e) {}
return [out];
